// ─── Settings Container ───────────────────────────────────────────────────────

.api-keys-settings {
  display: flex;
  flex-direction: column;
  gap: 0;

  @media (max-width: 1023px) {
    padding: 16px;
    padding-bottom: 100px;
  }
}

// ─── Two-column grid ──────────────────────────────────────────────────────────

.api-keys-settings__grid {
  display: grid;
  grid-template-columns: 3fr 4fr;
  gap: 10px;
  align-items: start;

  @media (max-width: 1023px) {
    grid-template-columns: 1fr;
    gap: 8px;
  }
}

// ─── Cards ────────────────────────────────────────────────────────────────────

.api-keys-settings__card {
  border-radius: 16px;
  overflow: hidden;

  &--dark {
    background: #141414;
    padding: 21px 2px 2px;
  }

  &--light {
    background: var(--color-content-bg);
    border: 1px solid var(--color-row-border);
    padding: 18px 18px 16px;

    @media (max-width: 1023px) {
      padding: 20px;
    }
  }
}

.api-keys-settings__card-title {
  font-size: 20px;
  font-weight: 500;
  color: #FFFFFF;
  margin: 0;
  padding: 0 20px 10px;
  line-height: 120%;

  &--light {
    color: #141414;
    padding: 0 0 18px;
  }
}

// ─── State messages ───────────────────────────────────────────────────────────

.api-keys-settings__state-msg {
  padding: 24px 20px;
  font-size: 14px;
  color: rgba(255, 255, 255, 0.35);
  margin: 0;
  text-align: center;
}

// ─── API Key List ─────────────────────────────────────────────────────────────

.api-keys-settings__list {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

// ─── API Key Item (white card inside dark container) ──────────────────────────

.api-key-item {
  background: #FFFFFF;
  border-radius: 14px;
  padding: 13px 18px 18px;
  display: flex;
  flex-direction: column;
  gap: 11px;

  &__header {
    display: flex;
    align-items: center;
    justify-content: space-between;
  }

  &__name {
    font-size: 16px;
    font-weight: 500;
    color: #111827;
    letter-spacing: -0.3125px;
    line-height: 24px;
    flex: 1;
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  &__delete {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 24px;
    height: 24px;
    flex-shrink: 0;
    border: none;
    background: none;
    color: #6B7280;
    cursor: pointer;
    border-radius: 4px;
    transition: color 0.15s;

    &:hover {
      color: #ef4444;
    }
  }

  &__key-row {
    display: flex;
    align-items: center;
    gap: 11px;
  }

  &__key-input {
    flex: 1;
    min-width: 0;
    height: 34px;
    padding: 5px 12px;
    border: 1px solid #E1E1E1;
    border-radius: 10px;
    font-size: 14px;
    font-weight: 500;
    color: #393939;
    background: transparent;
    outline: none;
    cursor: default;
    letter-spacing: 1.5px;
    box-sizing: border-box;

    &:focus {
      border-color: #E1E1E1;
    }
  }

  &__key-actions {
    display: flex;
    align-items: center;
    gap: 5px;
  }

  &__icon-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 24px;
    height: 24px;
    border: none;
    background: none;
    color: #141414;
    cursor: pointer;
    border-radius: 4px;
    transition: opacity 0.15s;

    &:hover {
      opacity: 0.6;
    }

    &--done {
      color: #10B981;
    }
  }

  &__footer {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 8px;
  }

  &__badges {
    display: flex;
    align-items: center;
    gap: 2px;
  }

  &__badge {
    display: inline-flex;
    align-items: center;
    padding: 3px 6px;
    border-radius: 6px;
    font-size: 12px;
    font-weight: 500;
    line-height: 16px;

    &--blue {
      background: #F1F5FE;
      color: #8EA9F9;
    }
  }

  &__date {
    font-family: 'Inter', sans-serif;
    font-size: 12px;
    font-weight: 400;
    color: #9CA3AF;
    line-height: 16px;
    white-space: nowrap;
    flex-shrink: 0;
  }
}

// ─── Security / AML ───────────────────────────────────────────────────────────

.api-keys-settings__aml {
  display: flex;
  align-items: flex-start;
  gap: 11px;
  cursor: pointer;
}

.api-keys-settings__aml-check {
  flex-shrink: 0;
  width: 24px;
  height: 24px;
  margin-top: 0;
  accent-color: #141414;
  cursor: pointer;
  border-radius: 4px;

  &:disabled {
    opacity: 0.5;
    cursor: default;
  }
}

.api-keys-settings__aml-body {
  display: flex;
  flex-direction: column;
  gap: 7px;
}

.api-keys-settings__aml-title {
  font-size: 16px;
  font-weight: 500;
  color: #141414;
  line-height: 24px;
  letter-spacing: -0.3125px;
}

.api-keys-settings__aml-desc {
  font-size: 14px;
  font-weight: 500;
  color: #9CA3AF;
  line-height: 140%;
}

// ─── Delete modal text ────────────────────────────────────────────────────────

.api-keys-settings__delete-msg {
  font-size: 14px;
  color: #555;
  line-height: 1.5;
  margin: 0 0 4px;
}

// ─── Mobile FAB ───────────────────────────────────────────────────────────────

.api-keys-settings__fab {
  display: none;

  @media (max-width: 1023px) {
    display: flex;
    align-items: center;
    gap: 8px;
    position: fixed;
    bottom: 88px;
    right: 20px;
    height: 48px;
    padding: 12px 18px 12px 12px;
    background: #8EA9F9;
    color: #fff;
    border: none;
    border-radius: 12px;
    font-size: 16px;
    font-weight: 500;
    cursor: pointer;
    z-index: 30;
    box-shadow: 0 4px 20px rgba(142, 169, 249, 0.4);
    transition: transform 0.15s, opacity 0.15s;

    &:active {
      transform: scale(0.95);
    }
  }
}

// ─── Create API Key Side Panel ────────────────────────────────────────────────

.cak-panel-backdrop {
  position: fixed;
  inset: 0;
  z-index: 100;
  background: linear-gradient(270deg, rgba(0, 0, 0, 0.18) 0%, rgba(0, 0, 0, 0) 100%);
  animation: modal-bg-in 0.15s ease-out;

  @media (max-width: 1023px) {
    background: rgba(0, 0, 0, 0.64);
  }
}

.cak-panel {
  position: fixed;
  top: 0;
  right: 0;
  bottom: 0;
  width: 481px;
  background: #FFFFFF;
  border-radius: 32px 0 0 32px;
  display: flex;
  flex-direction: column;
  z-index: 101;
  animation: cak-panel-in 0.25s ease-out;

  @media (max-width: 1023px) {
    width: 100%;
    border-radius: 18px 18px 0 0;
    top: auto;
    height: 542px;
    animation: cak-panel-up 0.25s ease-out;
  }

  &__header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 38px 35px 0;
    flex-shrink: 0;

    @media (max-width: 1023px) {
      padding: 30px 20px 0;
    }
  }

  &__title {
    font-size: 24px;
    font-weight: 600;
    color: #141414;
    line-height: 120%;
    margin: 0;
  }

  &__close-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 32px;
    height: 32px;
    border: none;
    background: none;
    cursor: pointer;
    border-radius: 6px;
    transition: background 0.15s;
    flex-shrink: 0;

    &:hover {
      background: rgba(0, 0, 0, 0.05);
    }
  }

  &__body {
    flex: 1;
    overflow-y: auto;
    padding: 24px 35px 16px;
    display: flex;
    flex-direction: column;
    gap: 12px;

    @media (max-width: 1023px) {
      padding: 20px 20px 16px;
    }
  }

  &__input {
    width: 100%;
    height: 48px;
    padding: 12px;
    border: 1px solid #E1E1E1;
    border-radius: 12px;
    font-size: 14px;
    font-weight: 400;
    color: #141414;
    background: transparent;
    outline: none;
    transition: border-color 0.2s;
    box-sizing: border-box;
    font-family: inherit;

    &::placeholder {
      color: #9CA3AF;
    }

    &:focus {
      border-color: #8EA9F9;
    }

    &:disabled {
      opacity: 0.6;
    }

    &--key {
      font-family: 'SF Mono', 'Fira Mono', 'Roboto Mono', monospace;
      font-size: 13px;
      color: #393939;
      cursor: default;
      letter-spacing: 0.3px;
      padding-right: 90px;
    }
  }

  &__select {
    width: 100%;
    height: 48px;
    padding: 12px;
    border: 1px solid #E1E1E1;
    border-radius: 12px;
    font-size: 14px;
    font-weight: 400;
    color: #9CA3AF;
    background: transparent;
    outline: none;
    appearance: none;
    background-image: url("data:image/svg+xml,%3Csvg width='12' height='8' viewBox='0 0 12 8' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1.5L6 6.5L11 1.5' stroke='%239CA3AF' stroke-width='1.5' stroke-linecap='round' stroke-linejoin='round'/%3E%3C/svg%3E");
    background-repeat: no-repeat;
    background-position: right 14px center;
    padding-right: 38px;
    cursor: pointer;
    box-sizing: border-box;
    font-family: inherit;

    &:disabled {
      opacity: 0.6;
    }
  }

  &__permissions {
    display: flex;
    flex-direction: column;
    gap: 10px;
    padding-top: 3px;
  }

  &__permissions-label {
    font-size: 14px;
    font-weight: 400;
    color: #6B7280;
    margin: 0;
    line-height: 120%;
  }

  &__permission {
    display: flex;
    align-items: center;
    gap: 7px;
    cursor: pointer;

    span {
      font-size: 16px;
      font-weight: 400;
      color: #111827;
      line-height: 130%;
    }
  }

  &__checkbox {
    width: 24px;
    height: 24px;
    flex-shrink: 0;
    margin: 0;
    accent-color: #141414;
    cursor: pointer;
  }

  &__error {
    font-size: 13px;
    color: #dc2626;
    margin: 0;
    padding: 8px 12px;
    background: rgba(239, 68, 68, 0.08);
    border-radius: 8px;
    font-weight: 500;
    line-height: 1.4;
  }

  &__warning {
    font-size: 13px;
    font-weight: 500;
    color: #92400e;
    background: rgba(245, 158, 11, 0.1);
    border-radius: 8px;
    padding: 10px 12px;
    margin: 0;
    line-height: 1.4;
  }

  &__key-wrap {
    position: relative;
    display: flex;
    align-items: center;
  }

  &__copy-btn {
    position: absolute;
    right: 6px;
    height: 32px;
    padding: 0 12px;
    border: none;
    border-radius: 8px;
    background: rgba(142, 169, 249, 0.1);
    color: #8EA9F9;
    font-size: 12px;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;

    &:hover {
      background: rgba(142, 169, 249, 0.18);
    }
  }

  &__footer {
    display: flex;
    align-items: center;
    gap: 5px;
    padding: 0 35px 29px;
    flex-shrink: 0;

    @media (max-width: 1023px) {
      padding: 0 20px 29px;
    }
  }

  &__cancel {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 118px;
    height: 48px;
    flex-shrink: 0;
    border: none;
    background: #F3F4F5;
    border-radius: 12px;
    font-size: 16px;
    font-weight: 500;
    color: #141414;
    cursor: pointer;
    font-family: inherit;
    transition: background 0.15s;

    &:hover:not(:disabled) {
      background: #E8E9EB;
    }

    &:disabled {
      opacity: 0.5;
      cursor: default;
    }

    @media (max-width: 1023px) {
      width: auto;
      padding: 0 20px;
    }
  }

  &__submit {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    height: 48px;
    border: none;
    background: #C6CEE6;
    border-radius: 12px;
    font-size: 16px;
    font-weight: 500;
    color: #E7EAF4;
    cursor: default;
    font-family: inherit;
    transition: background 0.15s, color 0.15s, opacity 0.15s;

    &--active {
      background: #8EA9F9;
      color: #FFFFFF;
      cursor: pointer;

      &:hover {
        opacity: 0.9;
      }
    }
  }
}

@keyframes cak-panel-in {
  from {
    transform: translateX(100%);
  }
  to {
    transform: translateX(0);
  }
}

@keyframes cak-panel-up {
  from {
    transform: translateY(100%);
  }
  to {
    transform: translateY(0);
  }
}

@keyframes modal-bg-in {
  from { opacity: 0; }
  to { opacity: 1; }
}

